        }))
      })),
      
      // === CARTERA/SERVICIOS ===
      cartera: {
        resumen: {
          total_contratado: contactData?.services?.reduce((sum, s) => 
            sum + s.valor_total, 0),
          total_pagado: contactData?.services?.reduce((sum, s) => 
