            monto: p.monto,
            fecha: p.fecha_pago,
            metodo: p.metodo_pago,
            estado: p.estado
          }))
        }))
      },
      
      // === FECHAS IMPORTANTES ===
      fechas_importantes: {
        creacion: contact.created_at,
        ultima_interaccion: contact.ultima_interaccion,
        primera_cita: contactData?.appointments?.slice(-1)[0]?.fecha_hora,
