### Schemas Disponibles

```typescript
import { 
  MonicaRequestSchema,
  CreateContactRequestSchema,
  CreateAppointmentRequestSchema,
  validateApiRequest 
} from '@/lib/api-schemas';
```

### Uso en API Routes

```typescript
import { validateApiRequest, MonicaRequestSchema } from '@/lib/api-schemas';

export async function POST(req: NextRequest) {
  // Validar request
  const validation = await validateApiRequest(req, MonicaRequestSchema);
  
  if (!validation.valid) {
    return validation.response; // 400 con detalles del error
  }
  
  const { message, context, history } = validation.data;
  
  // Procesar request validado...
}
```

